// Merge config from Master or Sheet reads (same pattern as WF1/WF3)
const webhookData = $('Webhook Trigger').first().json.body;

let config = {};
let performanceData = null;
let competitorData = null;

if (webhookData && webhookData.config) {
  // Master provided config + data
  config = webhookData.config;
  performanceData = webhookData.performance_data || null;
  competitorData = webhookData.competitor_data || null;
} else {
  // Standalone: build config from Sheet rows
  const konfigRows = $('Konfig aus Sheet lesen').all();
  for (const row of konfigRows) {
    const key = row.json['Einstellung'] || row.json['einstellung'];
    const val = row.json['Wert'] || row.json['wert'];
    if (key) config[key] = val;
  }
}

// Parse active platforms
const activePlatforms = (config.active_platforms || '')
  .split(',')
  .map(p => p.trim().toLowerCase())
  .filter(p => p.length > 0);

// Calendar week
const now = new Date();
const startOfYear = new Date(now.getFullYear(), 0, 1);
const days = Math.floor((now - startOfYear) / (24 * 60 * 60 * 1000));
const calendarWeek = Math.ceil((days + startOfYear.getDay() + 1) / 7);

// Initialize staticData for result accumulation
const staticData = $getWorkflowStaticData('global');
staticData.results = [];
staticData.errors = [];

return [{
  json: {
    config,
    activePlatforms,
    calendarWeek,
    year: now.getFullYear(),
    projectName: config.project_name || 'unknown',
    brandName: config.brand_name || '',
    brandDescription: config.brand_description || '',
    branche: config.branche || '',
    targetAudience: config.target_audience || '',
    brandTone: config.brand_tone || 'professionell, nahbar',
    performanceData,
    competitorData,
    needsSupabaseRead: !performanceData,
    timestamp: now.toISOString()
  }
}];

// Merge context data from Supabase reads or from Master-provided data
const configData = $('Konfig zusammenfuehren').first().json;

let performanceData = configData.performanceData;
let competitorData = configData.competitorData;

// If standalone, read from Supabase responses
if (!performanceData) {
  try {
    const perfResponse = $('Supabase Performance lesen').first().json;
    performanceData = Array.isArray(perfResponse) ? perfResponse : (perfResponse.data || []);
  } catch (e) {
    performanceData = [];
  }
}

if (!competitorData) {
  try {
    const compResponse = $('Supabase Competitor lesen').first().json;
    competitorData = Array.isArray(compResponse) ? compResponse : (compResponse.data || []);
  } catch (e) {
    competitorData = [];
  }
}

return [{
  json: {
    ...configData,
    performanceData,
    competitorData
  }
}];

// Create 1 item per active platform with platform-specific rules
const data = $input.first().json;

const PLATFORM_RULES = {
  instagram: {
    contentType: 'feed_post',
    needsImage: true,
    needsVideo: false,
    imageResolution: '1080x1350',
    maxCaptionChars: 125,
    hashtagCount: '3-5',
    tone: 'visuell, aspirativ, storytelling',
    rules: 'Max 125 Zeichen Caption. CTA in der ersten Zeile. 3-5 relevante Hashtags. Zusaetzlich: Reel-Konzept beschreiben (kurzes Video, vertikales Format). Emojis gezielt einsetzen.'
  },
  facebook: {
    contentType: 'feed_post',
    needsImage: true,
    needsVideo: false,
    imageResolution: '1080x1350',
    maxCaptionChars: 80,
    hashtagCount: '1-2',
    tone: 'konversationell, persoenlich, Fragen stellen',
    rules: '40-80 Zeichen Text. Max 1-2 Hashtags. Konversationeller Ton — Frage oder Geschichte erzaehlen. Teilen und Kommentare anregen.'
  },
  tiktok: {
    contentType: 'short',
    needsImage: false,
    needsVideo: true,
    videoFormat: '9:16',
    videoDuration: '15-30s',
    maxCaptionChars: 300,
    hashtagCount: '3-5 trending',
    tone: 'locker, unterhaltsam, trend-orientiert',
    rules: 'Video-Konzept im 9:16 Format, 15-30 Sekunden. Hook in den ersten 3 Sekunden. Keyword-reiche Caption. 3-5 trendende Hashtags. Beschreibe das Video-Skript Szene fuer Szene.'
  },
  linkedin: {
    contentType: 'article',
    needsImage: true,
    needsVideo: false,
    imageResolution: '1200x627',
    maxCaptionChars: 3000,
    maxPreviewChars: 140,
    hashtagCount: '2-3',
    tone: 'professionell, thought-leadership, Mehrwert',
    rules: 'Unter 140 Zeichen vor dem Mehr-Button (Teaser). Professioneller Ton, Thought Leadership. 2-3 Hashtags. Laengerer Text erlaubt (bis 3000 Zeichen), aber Teaser muss fesseln.'
  },
  youtube: {
    contentType: 'short',
    needsImage: false,
    needsVideo: true,
    videoFormat: '9:16',
    videoDuration: '15-60s',
    maxTitleChars: 70,
    hashtagCount: '0',
    tone: 'informativ, energetisch, Mehrwert',
    rules: 'Short-Konzept im 9:16 Format, 15-60 Sekunden. Max 70 Zeichen Titel. Keyword-reiche Beschreibung. Beschreibe das Video-Skript Szene fuer Szene. Call-to-Action: Abonnieren.'
  },
  x_twitter: {
    contentType: 'tweet',
    needsImage: true,
    needsVideo: false,
    imageResolution: '1600x900',
    maxCaptionChars: 280,
    targetCaptionChars: '70-100',
    hashtagCount: '1-2',
    tone: 'praegnant, meinungsstark, Gespraechsstarter',
    rules: '70-100 Zeichen optimal (max 280). 1-2 Hashtags. Praegnant und meinungsstark. Gespraechsstarter — Antworten provozieren. Kann auch als Thread geplant werden.'
  }
};

const items = [];

for (const platform of data.activePlatforms) {
  const rules = PLATFORM_RULES[platform];
  if (!rules) continue;

  // Find platform-specific performance data
  const perfForPlatform = (data.performanceData || []).find(
    p => p.platform === platform
  ) || {};

  // Find competitor insights for this platform
  const compForPlatform = (data.competitorData || []).filter(
    c => c.platform === platform
  );

  items.push({
    json: {
      platform,
      platformRules: rules,
      performanceContext: perfForPlatform,
      competitorContext: compForPlatform,
      projectName: data.projectName,
      brandName: data.brandName,
      brandDescription: data.brandDescription,
      branche: data.branche,
      targetAudience: data.targetAudience,
      brandTone: data.brandTone,
      calendarWeek: data.calendarWeek,
      year: data.year,
      timestamp: data.timestamp
    }
  });
}

if (items.length === 0) {
  items.push({
    json: {
      skip: true,
      reason: 'Keine aktiven Plattformen fuer Content-Erstellung'
    }
  });
}

return items;

// Build platform-specific Claude prompt for content generation
const item = $input.first().json;

// Skip if no valid platform
if (item.skip) {
  return [{ json: { skip: true, reason: item.reason } }];
}

const { platform, platformRules, performanceContext, competitorContext,
        brandName, brandDescription, branche, targetAudience, brandTone } = item;

// Build performance summary
let perfSummary = 'Keine Performance-Daten verfuegbar.';
if (performanceContext && performanceContext.followers) {
  perfSummary = `Aktuelle Metriken auf ${platform}:\n` +
    `- Follower: ${performanceContext.followers || 'N/A'}\n` +
    `- Impressions: ${performanceContext.impressions || 'N/A'}\n` +
    `- Engagement Rate: ${performanceContext.engagement_rate || 'N/A'}%\n` +
    `- Reach: ${performanceContext.reach || 'N/A'}\n` +
    `- Likes (Durchschnitt): ${performanceContext.avg_likes || 'N/A'}\n` +
    `- Kommentare (Durchschnitt): ${performanceContext.avg_comments || 'N/A'}`;
}

// Build competitor summary
let compSummary = 'Keine Wettbewerber-Insights verfuegbar.';
if (competitorContext && competitorContext.length > 0) {
  compSummary = 'Wettbewerber-Insights:\n';
  for (const comp of competitorContext.slice(0, 3)) {
    compSummary += `\n- ${comp.competitor_name || 'Unbekannt'}:\n`;
    compSummary += `  Followers: ${comp.followers || 'N/A'}, Engagement: ${comp.engagement_rate || 'N/A'}%\n`;
    if (comp.content_ideas) {
      const ideas = typeof comp.content_ideas === 'string' ? JSON.parse(comp.content_ideas) : comp.content_ideas;
      if (Array.isArray(ideas) && ideas.length > 0) {
        compSummary += `  Top Content-Ideen: ${ideas.slice(0, 2).join(', ')}\n`;
      }
    }
  }
}

// System prompt
const systemPrompt = `Du bist ein erfahrener Social Media Content Creator fuer den DACH-Markt. Du erstellst plattformspezifischen Content auf Deutsch.

Marke: ${brandName}
Beschreibung: ${brandDescription}
Branche: ${branche}
Zielgruppe: ${targetAudience}
Markenton: ${brandTone}

Dein Output ist IMMER ein valides JSON-Objekt mit exakt dieser Struktur:
{
  "caption": "Der fertige Post-Text/Caption",
  "hashtags": ["hashtag1", "hashtag2"],
  "cta": "Call-to-Action Text",
  "content_theme": "Kurze Beschreibung des Themas",
  "tone_description": "Beschreibung des verwendeten Tons",
  "image_prompt": "Englischer Prompt fuer Bildgenerierung (nur wenn Bild benoetigt)",
  "video_concept": "Detailliertes Video-Konzept Szene fuer Szene (nur wenn Video benoetigt)",
  "video_prompt": "Englischer Prompt fuer Videogenerierung (nur wenn Video benoetigt)"
}

WICHTIG: Antworte NUR mit dem JSON-Objekt, kein weiterer Text.`;

// User prompt
const userPrompt = `Erstelle einen Social Media Post fuer die Plattform: ${platform.toUpperCase()}

## Plattform-Regeln
${platformRules.rules}
Ton: ${platformRules.tone}
Content-Typ: ${platformRules.contentType}
${platformRules.needsImage ? 'Bild-Aufloesung: ' + platformRules.imageResolution : ''}
${platformRules.needsVideo ? 'Video-Format: ' + platformRules.videoFormat + ', Dauer: ' + platformRules.videoDuration : ''}

## Performance-Daten
${perfSummary}

## Wettbewerber-Insights
${compSummary}

## Aufgabe
Erstelle einen optimalen Post fuer ${platform}, der:
1. Die Plattform-Regeln exakt einhaelt (Zeichenlimit, Hashtag-Anzahl, Ton)
2. Auf den Performance-Daten aufbaut (was funktioniert? was verbessern?)
3. Wettbewerber-Insights beruecksichtigt (Differenzierung, Trends)
4. Zur Marke "${brandName}" passt
5. Die Zielgruppe "${targetAudience}" direkt anspricht
${platformRules.needsImage ? '6. Einen detaillierten englischen Bild-Prompt enthaelt (fuer AI-Bildgenerierung mit Imagen 4, beschreibe Stil, Komposition, Farben, Stimmung)' : ''}
${platformRules.needsVideo ? '6. Ein detailliertes Video-Konzept Szene fuer Szene enthaelt\n7. Einen englischen Video-Prompt enthaelt (fuer AI-Videogenerierung mit Veo 3)' : ''}

Antworte NUR mit dem JSON-Objekt.`;

return [{
  json: {
    ...item,
    systemPrompt,
    userPrompt
  }
}];

// Parse Claude response and extract content fields
const item = $input.first().json;

if (item.skip) {
  return [{ json: item }];
}

let content = {};

try {
  // Claude API response structure: { content: [{ type: 'text', text: '...' }] }
  const claudeResponse = item;
  let responseText = '';

  if (claudeResponse.content && Array.isArray(claudeResponse.content)) {
    responseText = claudeResponse.content
      .filter(c => c.type === 'text')
      .map(c => c.text)
      .join('');
  } else if (typeof claudeResponse === 'string') {
    responseText = claudeResponse;
  }

  // Extract JSON from response (handle potential markdown code blocks)
  let jsonStr = responseText.trim();
  if (jsonStr.startsWith('```')) {
    jsonStr = jsonStr.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
  }

  content = JSON.parse(jsonStr);
} catch (e) {
  content = {
    caption: 'Content-Generierung fehlgeschlagen: ' + e.message,
    hashtags: [],
    cta: '',
    content_theme: 'Fehler',
    tone_description: '',
    image_prompt: '',
    video_concept: '',
    video_prompt: ''
  };
}

// Retrieve original item data from previous node context
const promptData = $('Claude Prompt aufbauen').first().json;

return [{
  json: {
    platform: promptData.platform,
    platformRules: promptData.platformRules,
    projectName: promptData.projectName,
    brandName: promptData.brandName,
    calendarWeek: promptData.calendarWeek,
    year: promptData.year,
    performanceContext: promptData.performanceContext,
    competitorContext: promptData.competitorContext,
    generatedContent: content,
    rawClaudeResponse: item,
    systemPrompt: promptData.systemPrompt,
    userPrompt: promptData.userPrompt
  }
}];

// Parse Imagen 4 response and attach image data
const item = $input.first().json;
const prevData = $('Claude Response parsen').first().json;

let imageData = {
  imageUrl: null,
  imageBase64: null,
  imageResolution: prevData.platformRules.imageResolution
};

try {
  // Imagen 4 response: { predictions: [{ bytesBase64Encoded: '...' }] }
  if (item.predictions && item.predictions.length > 0) {
    imageData.imageBase64 = item.predictions[0].bytesBase64Encoded || null;
  }
  // Alternative response format: { images: [{ image: { imageBytes: '...' } }] }
  if (!imageData.imageBase64 && item.images && item.images.length > 0) {
    imageData.imageBase64 = item.images[0].image?.imageBytes || null;
  }
  // Alternative: generatedImages format
  if (!imageData.imageBase64 && item.generatedImages && item.generatedImages.length > 0) {
    imageData.imageBase64 = item.generatedImages[0].image?.imageBytes || null;
  }
} catch (e) {
  // Image generation failed -- continue with text-only content
}

return [{
  json: {
    ...prevData,
    imageData,
    rawImagenResponse: item
  }
}];

// Pass through data without image -- for video-only platforms
const prevData = $('Claude Response parsen').first().json;

return [{
  json: {
    ...prevData,
    imageData: { imageUrl: null, imageBase64: null, imageResolution: null },
    rawImagenResponse: null
  }
}];

// Parse Veo 3 response and extract video data
const item = $input.first().json;
const prevData = $('Braucht Video?').first().json;

let videoData = {
  videoUrl: null,
  videoConcept: prevData.generatedContent.video_concept || '',
  videoPrompt: prevData.generatedContent.video_prompt || '',
  videoDuration: prevData.platformRules.videoDuration || '',
  videoFormat: prevData.platformRules.videoFormat || '9:16'
};

try {
  // Check if operation is done
  if (item.done === true && item.response) {
    // Completed: extract video URL
    const videos = item.response.generatedVideos || item.response.videos || [];
    if (videos.length > 0) {
      videoData.videoUrl = videos[0].video?.uri || videos[0].uri || null;
    }
  } else if (item.generatedVideos && item.generatedVideos.length > 0) {
    // Direct response format
    videoData.videoUrl = item.generatedVideos[0].video?.uri || null;
  }
} catch (e) {
  // Video generation failed -- concept is still available
}

return [{
  json: {
    ...prevData,
    videoData,
    rawVeoResponse: item
  }
}];

// Pass through data without video -- for image-only platforms
const item = $input.first().json;

return [{
  json: {
    ...item,
    videoData: { videoUrl: null, videoConcept: '', videoPrompt: '', videoDuration: '', videoFormat: '' },
    rawVeoResponse: null
  }
}];

// Collect result into staticData for final aggregation
const item = $input.first().json;
const staticData = $getWorkflowStaticData('global');

if (!staticData.results) staticData.results = [];
if (!staticData.errors) staticData.errors = [];

if (item.skip) {
  // Skipped platform
  return [{ json: { collected: true } }];
}

try {
  const result = {
    platform: item.platform,
    contentType: item.platformRules.contentType,
    caption: item.generatedContent.caption || '',
    hashtags: item.generatedContent.hashtags || [],
    cta: item.generatedContent.cta || '',
    contentTheme: item.generatedContent.content_theme || '',
    toneDescription: item.generatedContent.tone_description || '',
    imagePrompt: item.generatedContent.image_prompt || '',
    imageResolution: item.imageData?.imageResolution || null,
    imageBase64: item.imageData?.imageBase64 || null,
    imageUrl: item.imageData?.imageUrl || null,
    videoConcept: item.videoData?.videoConcept || '',
    videoPrompt: item.videoData?.videoPrompt || '',
    videoUrl: item.videoData?.videoUrl || null,
    videoDuration: item.videoData?.videoDuration || '',
    videoFormat: item.videoData?.videoFormat || '',
    charCount: (item.generatedContent.caption || '').length,
    hashtagCount: (item.generatedContent.hashtags || []).length,
    projectName: item.projectName,
    calendarWeek: item.calendarWeek,
    year: item.year
  };

  staticData.results.push(result);
} catch (e) {
  staticData.errors.push({
    platform: item.platform || 'unknown',
    error: e.message,
    timestamp: new Date().toISOString()
  });
}

return [{ json: { collected: true } }];

// Prepare final results from staticData for persistence
const staticData = $getWorkflowStaticData('global');
const results = staticData.results || [];
const errors = staticData.errors || [];

// Clean up staticData
delete staticData.results;
delete staticData.errors;

// Build Supabase UPSERT rows
const supabaseRows = results.map(r => ({
  project_name: r.projectName,
  calendar_week: r.calendarWeek,
  year: r.year,
  platform: r.platform,
  content_type: r.contentType,
  caption: r.caption,
  hashtags: r.hashtags,
  cta_text: r.cta,
  char_count: r.charCount,
  hashtag_count: r.hashtagCount,
  image_prompt: r.imagePrompt,
  image_url: r.imageUrl,
  image_base64: r.imageBase64 ? '(base64 data stored)' : null,
  image_resolution: r.imageResolution,
  video_prompt: r.videoPrompt,
  video_url: r.videoUrl,
  video_concept: r.videoConcept,
  video_duration_target: r.videoDuration,
  video_format: r.videoFormat,
  tone_description: r.toneDescription,
  content_theme: r.contentTheme,
  status: 'draft',
  data_source: 'wf4_content_creator'
}));

// Build Sheet rows
const sheetRows = results.map(r => ({
  Plattform: r.platform,
  ContentTyp: r.contentType,
  Caption: r.caption,
  Hashtags: (r.hashtags || []).join(', '),
  CTA: r.cta,
  Thema: r.contentTheme,
  Ton: r.toneDescription,
  BildAufloesung: r.imageResolution || '-',
  BildPrompt: r.imagePrompt || '-',
  VideoKonzept: r.videoConcept || '-',
  VideoDauer: r.videoDuration || '-',
  Status: 'Entwurf',
  KW: r.calendarWeek,
  Jahr: r.year,
  Erstellt: new Date().toISOString()
}));

return [{
  json: {
    results,
    errors,
    supabaseRows,
    sheetRows,
    totalPlatforms: results.length,
    totalErrors: errors.length,
    projectName: results.length > 0 ? results[0].projectName : 'unknown'
  }
}];

// Build structured response
const resultData = $('Ergebnisse aufbereiten').first().json;

const hasErrors = (resultData.errors || []).length > 0;

return [{
  json: {
    success: !hasErrors || resultData.totalPlatforms > 0,
    workflow: 'WF4_Content_Creator',
    data: {
      totalPlatforms: resultData.totalPlatforms,
      platforms: (resultData.results || []).map(r => ({
        platform: r.platform,
        contentType: r.contentType,
        captionPreview: (r.caption || '').substring(0, 100) + ((r.caption || '').length > 100 ? '...' : ''),
        hashtagCount: r.hashtagCount,
        hasImage: !!(r.imageBase64 || r.imageUrl),
        hasVideo: !!r.videoUrl,
        hasVideoConcept: !!r.videoConcept
      })),
      projectName: resultData.projectName
    },
    errors: resultData.errors || [],
    timestamp: new Date().toISOString()
  }
}];
